dashboard.definition:
{
  "title": "Upstream Alerts",
  "description": "",
  "defaults": {
    "dataSources": {
      "ds.search": {
        "options": {
          "queryParameters": {
            "earliest": "-30d@d",
            "latest": "now"
          }
        }
      }
    },
    "visualizations": {
      "global": {
        "showProgressBar": true
      }
    }
  },
  "visualizations": {
    "viz_6eUhRw7U": {
      "dataSources": {
        "primary": "ds_ER0lzS21"
      },
      "options": {
        "center": [
          28.500304035064843,
          4.419083926796134
        ],
        "layers": [
          {
            "additionalTooltipFields": [
              "ALERTS"
            ],
            "bubbleSize": "> primary | frameWithoutSeriesNames('geobin', 'latitude', 'longitude') | frameBySeriesTypes('number')",
            "seriesColors": [
              "#d93912",
              "#009CEB",
              "#00CDAF",
              "#DD9900",
              "#FF677B",
              "#CB2196",
              "#813193",
              "#0051B5",
              "#008C80",
              "#99B100",
              "#FFA476",
              "#FF6ACE",
              "#AE8CFF",
              "#00689D",
              "#00490A",
              "#465D00",
              "#9D6300",
              "#F6540B",
              "#FF969E",
              "#E47BFE"
            ],
            "tooltipHeaderField": "> primary | seriesByName('geobin')",
            "type": "bubble"
          }
        ],
        "zoom": 0.3
      },
      "showLastUpdated": false,
      "showProgressBar": true,
      "title": "",
      "type": "splunk.map"
    },
    "viz_BI3nIy4t": {
      "containerOptions": {
        "title": {
          "color": "#f1813f"
        }
      },
      "dataSources": {
        "primary": "ds_fvd3cJde"
      },
      "options": {
        "backgroundColor": "#031026",
        "majorColor": "#f1813f",
        "majorValue": "> primary | seriesByName('HIGH') | lastPoint()",
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      },
      "showLastUpdated": false,
      "showProgressBar": false,
      "title": "HIGH",
      "type": "splunk.singlevalue"
    },
    "viz_K7U1kdnr": {
      "containerOptions": {
        "title": {
          "color": "#dc4e41"
        }
      },
      "dataSources": {
        "primary": "ds_fvd3cJde"
      },
      "options": {
        "backgroundColor": "#031026",
        "majorColor": "#dc4e41",
        "majorValue": "> primary | seriesByName('CRITICAL') | lastPoint()",
        "sparklineDisplay": "off",
        "trendDisplay": "off"
      },
      "showLastUpdated": false,
      "showProgressBar": false,
      "title": "CRITICAL",
      "type": "splunk.singlevalue"
    },
    "viz_L6Rqewt9": {
      "containerOptions": {
        "title": {
          "color": "#000000"
        }
      },
      "dataSources": {
        "fieldsummary": "ds_jjwAJAFJ",
        "primary": "ds_klIPQcsu"
      },
      "eventHandlers": [
        {
          "options": {
            "newTab": false,
            "type": "auto"
          },
          "type": "drilldown.linkToSearch"
        }
      ],
      "options": {
        "backgroundColor": "#031026",
        "columnFormat": {
          "NAME": {
            "width": 174
          },
          "SEVERITY": {
            "width": 60
          },
          "VEHICLE MODEL": {
            "width": 60
          }
        },
        "count": 15,
        "fontSize": "large",
        "tableFormat": {
          "align": "center",
          "headerAlign": "center",
          "headerBackgroundColor": "> backgroundColor | setColorChannel(tableHeaderBackgroundColorConfig)",
          "headerColor": "> headerBackgroundColor | maxContrast(tableRowColorMaxContrast)",
          "rowBackgroundColors": "> table | seriesByIndex(0) | pick(tableAltRowBackgroundColorsByBackgroundColor)",
          "rowColors": "> rowBackgroundColors | maxContrast(tableRowColorMaxContrast)"
        }
      },
      "showLastUpdated": false,
      "showProgressBar": true,
      "type": "splunk.table"
    },
    "viz_U5GkKDCB": {
      "dataSources": {
        "primary": "ds_PP1qZkyB"
      },
      "options": {
        "backgroundColor": "#031026",
        "label": "> primary | seriesByName('SEVERITY')",
        "labelDisplay": "valuesAndPercentage",
        "showDonutHole": true
      },
      "showLastUpdated": false,
      "showProgressBar": true,
      "title": "SEVERITY",
      "type": "splunk.pie"
    },
