  "dataSources": {
    "ds_0RxIRjYI": {
      "name": "KPI High_4_1",
      "options": {
        "extend": "ds_wCimX60S",
        "query": "| eval value=HIGH | fillnull value=0 | fields value"
      },
      "type": "ds.chain"
    },
    "ds_0ZoIp5Mi": {
      "name": "Events 1 search_5",
      "options": {
        "enableSmartSources": true,
        "query": "index=main\n| spath path=alert.name output=name\n| spath path=alert.id.value output=id\n| spath path=alert.detectorType output=detectorType\n| spath path=alert.country output=country\n| spath path=alert.vehicleModel output=vehicleModel\n| spath path=alert.severity output=severity\n| eval time=strftime(_time, \"%Y-%m-%d %H:%M:%S\")\n\n| eval severity=upper(severity)\n\n| eval severity_icon=case(\n    severity=\"LOW\",    \"🟡 LOW 🟡\",\n    severity=\"MEDIUM\", \"🟠 MEDIUM 🟠\",\n    severity=\"HIGH\", \"🔴 HIGH 🔴\",\n    severity=\"CRITICAL\", \"🟥 CRITICAL 🟥\",\n    1=1, severity\n)\n\n| dedup id\n| sort 0 - id\n\n| table time name id detectorType country vehicleModel severity_icon\n\n| rename time as \"TIME\"\n       name as \"NAME\"\n       id as \"ID\"\n       detectorType as \"DETECTOR TYPE\"\n       country as \"COUNTRY\"\n       vehicleModel as \"VEHICLE MODEL\"\n       severity_icon as \"SEVERITY\"\n",
        "queryParameters": {
          "earliest": "-30d@d",
          "latest": "now",
          "sampleRatio": 1
        }
      },
      "type": "ds.search"
    },
    "ds_0qf95RDH": {
      "name": "KPI High_1",
      "options": {
        "extend": "ds_Y0VNVL61",
        "query": "| eval value=HIGH | fillnull value=0 | fields value"
      },
      "type": "ds.chain"
    },
    "ds_1B6rlsJi": {
      "name": "Severities_4",
      "options": {
        "enableSmartSources": true,
        "query": "index=main\n| spath path=alert.severity output=severity\n| eval severity=upper(coalesce(severity, \"UNKNOWN\"))\n| stats count as value by severity\n| rename severity as SEVERITY\n| sort - value\n",
        "queryParameters": {
          "earliest": "-30d@d",
          "latest": "now"
        }
      },
      "type": "ds.search"
    },
    "ds_1Iqk0kEt": {
