      "name": "Top alert names_1_1",
      "options": {
        "query": "index=main\n| spath path=alert.id.value output=id\n| spath path=alert.name output=name\n| where isnotnull(name)\n| stats dc(id) as ALERTS by name\n| sort 0 - ALERTS\n| head 10\n| rename name as NAME\n"
