        "query": "| stats dc(eval(if(severity=\"CRITICAL\", id, null()))) as CRITICAL dc(eval(if(severity=\"HIGH\", id, null()))) as HIGH dc(eval(if(severity=\"MEDIUM\", id, null()))) as MEDIUM dc(eval(if(severity=\"LOW\", id, null()))) as LOW\n"
