        "query": "index=main\n| timechart span=1h count as ALERTS\n| sort 0 _time\n",
        "queryParameters": {
          "earliest": "-30d@d",
          "latest": "now"
        }
      },
      "type": "ds.search"
    },
    "ds_ui75LpYo": {
      "name": "Base events_1",
      "options": {
        "enableSmartSources": true,
        "query": "index=main\n| spath path=alert.id.value output=id\n| spath path=alert.name output=name\n| spath path=alert.severity output=severity\n| spath path=alert.location.coordinates{} output=coords\n| eval name=coalesce(name, \"UNKNOWN\")\n| eval severity=upper(coalesce(severity, \"UNKNOWN\"))\n| where isnotnull(id)\n| fields _time id name severity coords\n",
        "queryParameters": {
          "earliest": "-30d@d",
          "latest": "now",
          "sampleRatio": 1
        }
      },
      "type": "ds.search"
    },
    "ds_v0EFUuYL": {
      "name": "Severity pie (from KPI base)_1",
      "options": {
        "extend": "ds_wCimX60S",
        "query": "| fields CRITICAL HIGH MEDIUM LOW UNKNOWN\n| untable dummy severity value\n| where severity!=\"dummy\"\n| eval SEVERITY=severity\n| fields SEVERITY value\n| sort - value\n"
      },
      "type": "ds.chain"
    },
